external_knowledge:
- "branches of the organizational tree" metaphorically refers to departments in an organization;
- "bear the heaviest fruit" symbolizes departments with the highest count of devices;
- "sown the most devices" means departments that have the most devices associated with their users.

sql:
SELECT DISTINCT devices.device_name, users.user_name 
FROM devices 
JOIN users ON devices.primary_user_upn = users.user_upn;

SELECT devices.location, users.user_name
FROM devices
INNER JOIN users ON devices.primary_user_upn = users.user_upn;

SELECT M.manager_name, D.department_name
FROM managers M
INNER JOIN departments D ON M.department_id = D.department_id;

SELECT device_name
FROM devices
WHERE managed_by = 'Intune';

SELECT d.device_id, d.device_name, d.last_check_in, d.primary_user_upn
FROM devices d
WHERE (julianday('now') - julianday(d.last_check_in)) > 30;

SELECT device_name, primary_user_upn
FROM devices
WHERE compliance = 'Out of Compliance';

SELECT device_name, device_id, compliance, last_check_in, last_software_update
FROM devices
WHERE primary_user_upn = '<specific_user_upn>';

SELECT devices.device_name, compliance_checks.check_date, compliance_checks.compliance_status
FROM devices
JOIN compliance_checks ON devices.device_id = compliance_checks.device_id;

external_knowledge:
- 'gadgets' refer to devices in the organization's inventory;
- 'main operators' refer to primary users of those devices;
- 'status' includes compliance, employment, and ownership status;
- 'personal information' includes the user's name, email, department, phone, position, and hire date.

sql:
SELECT os_name
FROM os_types
WHERE os_id = (SELECT MAX(os_type_id) FROM devices);

SELECT device_name, managed_by, ownership, compliance, os, os_version
FROM devices
WHERE ownership = 'Personal';

SELECT device_id, device_name, compliance, location
FROM devices
WHERE managed_by = 'Intune' AND ownership = 'Corporate';
